val name = user.name // error: nullable receiver

// AFTER (option 1 — safe call):
val name = user?.name

// AFTER (option 2 — smart cast):
if (user != null) {
    val name = user.name // smart-casted to non-null
}

// AFTER (option 3 — Elvis):
val name = user?.name ?: "unknown"

// BEFORE:
class Foo {
    var name: String? = null
    fun test() {
        if (name != null) {
            name.length // smart cast impossible — var can change
        }
    }
}

// AFTER:
class Foo {
    var name: String? = null
    fun test() {
        val localName = name // capture in local val
        if (localName != null) {
            localName.length // smart cast works
        }
    }
}

